@app.route('/reset-password', methods=['POST'])
def reset_password():
    data = request.get_json()
    token = data.get('token', '')
    new_password = data.get('password', '')
    
    if not token or not new_password:
        return jsonify({'message': 'Token and password required'}), 400
    
    # Validate token
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT email, created_at FROM password_resets WHERE token = ? AND used = FALSE", (token,))
    result = c.fetchone()
    
    if not result:
        conn.close()
        return jsonify({'message': 'Invalid or expired token'}), 400
    
    email, created_at = result
    # Check if token is older than 1 hour
    if datetime.now() - created_at > timedelta(hours=1):
        conn.close()
        return jsonify({'message': 'Token expired'}), 400
    
    # Mark token as used
    c.execute("UPDATE password_resets SET used = TRUE WHERE token = ?", (token,))
    conn.commit()
    conn.close()
    
    # Update password (insecure - use proper hashing in production)
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("UPDATE users SET password = ? WHERE email = ?", (new_password, email))
    conn.commit()
    conn.close()
    
    return jsonify({'message': 'Password reset successfully'}), 200

